                String[] fields = line.split(",");
                return new Tuple2<>(fields[0], fields[1]);
            }
        });

        // Convert top frequent queries to a set for quick lookup
        JavaRDD<String> topFrequentQueriesSet = topFrequentQueries.map(new Function<String, String>() {
            @Override
